CREATE proc [dbo].[TblAdminUserDA_SrchByLoginIDandPW]
			@login_id nvarchar(50),
			@login_pw nvarchar(50)
		as
			set transaction isolation level read uncommitted
			set ansi_warnings off			
			
			select admin_level, datediff(dd, PWDATE, getdate()) pwday, admin_id, login_id, login_nm, login_pw, login_email, is_deleted, organization_id, convert(nvarchar,regdate,20) regdate
			from tbl_admin_user (nolock)
			where is_deleted='Y'  and login_id = ''+@login_id+'' and [login_pw] COLLATE KOREAN_WANSUNG_CS_AS = ''+@login_pw+''

CREATE proc [dbo].[TblAdminUserDAO_CreateGM]
			@login_id nvarchar(150),	
			@login_pw nvarchar(150),
			@login_nm nvarchar(150),
			@login_email nvarchar(170),
			@organization_id nvarchar(50),			
			@is_deleted nvarchar(2),
			@etc nvarchar(200),
			@admin_level tinyint
		as
			INSERT INTO TBL_ADMIN_USER (login_id, login_pw, login_nm, login_email, organization_id, is_deleted, etc, regdate, pwdate, admin_level, auth_update_date)
			VALUES(@login_id, @login_pw, @login_nm, @login_email,@organization_id, @is_deleted, @etc, getdate(), getdate(), @admin_level, getdate())

CREATE proc [dbo].[TblAdminUserDAO_UpdateGMState]
			@admin_id nvarchar(10),
			@is_deleted nvarchar(2)
		as
			UPDATE TBL_ADMIN_USER SET IS_DELETED = @is_deleted, AUTH_UPDATE_DATE = GETDATE() WHERE ADMIN_ID = @admin_id

create proc [dbo].[TblAdminUserDAO_UpdateMyGM]
			@admin_id nvarchar(10),
			@login_pw nvarchar(150),			
			@login_email nvarchar(170),			
			@etc nvarchar(200)	
		as
			UPDATE TBL_ADMIN_USER SET PWDATE=getdate(), login_pw = @login_pw, login_email = @login_email, etc = @etc
			WHERE ADMIN_ID = @admin_id

	
