create proc [dbo].[TblQuestDA_SrchMyQuest]	
			@world_id nvarchar(5),
			@char_id nvarchar(20),				
			@account_id nvarchar(20)
		as
		set nocount on
		set transaction isolation level read uncommitted
		set ansi_warnings off
		
		select *
		from TBL_QUEST(nolock)
		where world_id = @world_id and char_id = @char_id and account_id = @account_id order by quest_pk desc
		
		set nocount off
		return

